INSERT INTO questions (
  id,
  pattern_id,
  symbol,
  market,
  timeframe,
  difficulty,
  market_regime,
  base_date,
  chart_data,
  actual_next_candles,
  correct_answer,
  ai_explanation,
  rule_score,
  public_accuracy,
  pattern_evidence,
  pattern_score_breakdown,
  is_synthetic,
  source_name,
  source_url,
  source_symbol,
  source_exchange,
  source_date_range
)
SELECT
  rq.id,
  p.id,
  rq.symbol,
  'KRX',
  '1d',
  rq.difficulty,
  'volatile'::market_regime,
  rq.base_date,
  rq.chart_data,
  rq.actual_next_candles,
  rq.correct_answer,
  rq.ai_explanation,
  rq.rule_score,
  0.7000,
  rq.pattern_evidence,
  rq.pattern_score_breakdown,
  false,
  'Yahoo Finance chart API',
  rq.source_url,
  rq.source_symbol,
  rq.source_exchange,
  rq.source_date_range
FROM real_questions rq
CROSS JOIN pattern_row p
ON CONFLICT (id) DO UPDATE SET
  pattern_id = EXCLUDED.pattern_id,
  symbol = EXCLUDED.symbol,
  market = EXCLUDED.market,
  timeframe = EXCLUDED.timeframe,
  difficulty = EXCLUDED.difficulty,
  market_regime = EXCLUDED.market_regime,
